// Detecta quais tabelas Supabase consultar com base na mensagem
const msg = ($input.first().json.message ?? '').toLowerCase();

const tables = [];

if (
  msg.includes('pep') ||
  msg.includes('orçamento') ||
  msg.includes('orcamento') ||
  msg.includes('wbs') ||
  msg.includes('componente') ||
  msg.includes('produto') ||
  msg.includes('subproduto') ||
  msg.includes('plano de trabalho') ||
  msg.includes('execução') ||
  msg.includes('execucao')
) tables.push('pep_entries');

if (
  msg.includes('risco') ||
  msg.includes('ameaça') ||
  msg.includes('ameaca') ||
  msg.includes('vulnerabilidade')
) tables.push('riscos');

if (
  msg.includes('aquisição') ||
  msg.includes('aquisicao') ||
  msg.includes('contrato') ||
  msg.includes('licitação') ||
  msg.includes('licitacao') ||
  msg.includes('compra') ||
  msg.includes('fornecedor')
) tables.push('aquisicoes');

if (
  msg.includes('pmr') ||
  msg.includes('indicador') ||
  msg.includes('output') ||
  msg.includes('meta') ||
  msg.includes('resultado')
) tables.push('pmr_outputs', 'pmr_outcomes');

if (
  msg.includes('atividade') ||
  msg.includes('ação') ||
  msg.includes('acao') ||
  msg.includes('tarefa')
) tables.push('atividades');

if (
  msg.includes('marco') ||
  msg.includes('prazo') ||
  msg.includes('cronograma') ||
  msg.includes('data')
) tables.push('marcos');

if (
  msg.includes('ponto de atenção') ||
  msg.includes('ponto de atencao') ||
  msg.includes('alerta') ||
  msg.includes('problema')
) tables.push('pontos_atencao');

if (
  msg.includes('não-objeção') ||
  msg.includes('nao-objecao') ||
  msg.includes('aprovação bid') ||
  msg.includes('aprovacao bid')
) tables.push('nao_objecoes');

if (tables.length === 0) {
  tables.push('pep_entries', 'riscos');
}

return [{ json: { tables: [...new Set(tables)], message: $input.first().json.message } }];

