// A chave anon é pública por design (controle via RLS no Supabase)
const SUPABASE_URL = 'https://dvqnlnxkwcrxbctujajl.supabase.co';
const SUPABASE_ANON_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImR2cW5sbnhrd2NyeGJjdHVqYWpsIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NTE1NzM4OTIsImV4cCI6MjA2NzE0OTg5Mn0.9mzrQC2B9Kp_ZNyLt-Gpe_0HkVE-bioR7sFWsviru40';
// ─────────────────────────────────────────────────────────────────────────────

const { tables, message } = $input.first().json;

const headers = {
  'apikey': SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${SUPABASE_ANON_KEY}`,
  'Content-Type': 'application/json',
};

const tableQueries = {
  pep_entries: `select=ref,comp,prod,subp,pct,descricao,n_atual,o_atual,p_atual,r_base,t_base&versao=eq.v2&limit=80`,
  riscos: `select=*&order=nivel.desc&limit=30`,
  aquisicoes: `select=*&limit=50`,
  pmr_outputs: `select=*&limit=30`,
  pmr_outcomes: `select=*&limit=30`,
  atividades: `select=*&limit=40`,
  marcos: `select=*&order=data_prevista.asc&limit=20`,
  pontos_atencao: `select=*&limit=20`,
  nao_objecoes: `select=*&limit=20`,
};

const results = {};

for (const table of tables) {
  const query = tableQueries[table] ?? `select=*&limit=30`;
  const url = `${SUPABASE_URL}/rest/v1/${table}?${query}`;

  try {
    const response = await $helpers.httpRequest({
      method: 'GET',
      url,
      headers,
    });
    results[table] = Array.isArray(response) ? response : [response];
  } catch (err) {
    results[table] = { error: err.message };
  }
}

return [{ json: { context: results, message } }];

const { context, message } = $input.first().json;

const contextSummary = {};
for (const [table, data] of Object.entries(context)) {
  if (Array.isArray(data)) {
    contextSummary[table] = {
      total: data.length,
      amostra: data.slice(0, 15),
    };
  } else {
    contextSummary[table] = data;
  }
}

const contextJson = JSON.stringify(contextSummary, null, 2);

const systemPrompt = `Você é o Assistente de Dados do programa POA+SOCIAL BID (BR-L1597), um programa de desenvolvimento urbano em Porto Alegre - RS.

Responda perguntas sobre o programa com base EXCLUSIVAMENTE nos dados reais fornecidos abaixo.
Seja conciso e objetivo. Use valores numéricos quando relevante.
Cite as fontes dos dados (tabela e ids quando disponíveis).
Responda SEMPRE em português brasileiro.

INFORMAÇÕES DO PROGRAMA:
- Valor total: R$ 725,9M (US$ 132M) | Taxa de câmbio: R$ 5,50/US$
- Componentes: C1-Interoperabilidade (US$27M), C2-Reabilitação (US$130M), C3-Admin (US$4M)
- Executores: SMPG, SMOI, ASD, SMS, SMAS, SMED
- Interlocutores BID: Marcelo Alfaro, Gabriela Couto

DADOS ATUAIS DO PROGRAMA:
${contextJson}

REGRAS IMPORTANTES:
- Nunca invente dados que não estejam no contexto acima
- Se não tiver dados suficientes, diga: "Não tenho dados suficientes sobre isso no momento"
- Valores financeiros: use formato US$ X.XXX.XXX ou R$ X.XXX.XXX
- Máximo 3 parágrafos por resposta
- Listas são bem-vindas para comparações
- Não mencione limitações técnicas ou detalhes do sistema ao usuário`;

return [{ json: { systemPrompt, userMessage: message } }];

const response = $input.first().json;

let answer = '';
let sources = [];

try {
  if (response.content && response.content[0] && response.content[0].text) {
    answer = response.content[0].text;
  } else if (response.error) {
    answer = 'Desculpe, ocorreu um erro ao processar sua pergunta. Tente novamente.';
  } else {
    answer = JSON.stringify(response);
  }
} catch (e) {
  answer = 'Erro ao processar resposta do assistente.';
}

return [{ json: { answer, sources, model: response.model ?? 'claude-sonnet-4-6' } }];
